array_map(
			function( $item ) {
				if ( substr( $item, 0, 1 ) !== '/' ) {
					$item = '/' . $item;
				}

				return preg_replace( '~/$~', '/*', $item );
			}, $exclude_list_array
		)

$this->wpdb->get_results(
			$this->wpdb->prepare( //phpcs:ignore
				sprintf("
				SELECT option_name
				FROM %s
				WHERE autoload IN (%s)
				AND option_name NOT IN ( " . implode( ',', array_map( function( $item ) {
					return "'" . esc_sql( $item ) . "'";
				}, $excludes )
				) . " )
				ORDER BY LENGTH(option_value) DESC
				LIMIT 1",
				$this->wpdb->options,
				implode( ',', array_fill( 0, count( $autoload_values ), '%s' ) ) ),
				$autoload_values
			)
		)

array_map(
			function( $item ) {
				return str_replace( '\*', '.*', preg_quote( str_replace( home_url(), '', $item ), '/' ) );
			}, $excluded_urls
		)

array_filter(
			array_merge(
				$modules, // Add "What's new" modules.
				array_merge(
					array(
						$this->get_optimizations(), // Add optimizations that are not yet enabled to the response.
					),
					// Add the default card.
					array(
						array(
							'type'       => 'default',
							'title'      => __( 'Welcome to Speed Optimizer by SiteGround', 'sg-cachepress' ),
							'text'       => __( 'Get the best performance for your WordPress website with our optimization plugin. It handles caching, system settings, and all the necessary configurations for a blazing-fast website. With the Speed Optimizer by SiteGround enabled, you’re getting the very best from your hosting environment!', 'sg-cachepress' ),
							'icon'       => 'presentational-speed-caching',
							'icon_color' => 'salmon',
						),
					)
				)
			)
		)

wp_send_json_error(
				array(
					'message' => __( 'Speed Optimizer by SiteGround was unable to connect to the Memcached server and it was disabled. Please, check your SiteGround control panel and turn it on if disabled.', 'sg-cachepress' ),
				)
			)

wp_send_json_error(
					array(
						'message' => __( 'Speed Optimizer by SiteGround was unable to connect to the Memcached server and it was disabled. Please, check your SiteGround control panel and turn it on if disabled.', 'sg-cachepress' ),
					)
				)

array_map(
            function ($translation) {
                if (!empty($translation)) {
                    for ($i = 2; $i < count($translation); $i++) {
                        if (isset($translation[$i]) && empty($translation[$i])) {
                            $translation[$i] = $translation[0];
                        }
                    }
                    array_shift($translation);
                }

                return $translation;
            },
            $translations
        )

wp_remote_post(
				self::API_URL . '/auth/get_authenticated_response',
				array(
					'timeout' => 10,
					'body' => json_encode(
						array( 'url' => home_url() )
					),
					'sslverify' => false,
				)
			)

